/**
 * Execute chat with a single agent
 */
async function* executeSingleAgent(
  agentId: string,
  request: ChatRequest,
  command: AgentCommand | null,
  abortController: AbortController,
  debugMode: boolean
): AsyncGenerator<StreamResponse> {
  yield* executeAgentConversation(
    agentId,
    request.message,
    request,
    command,
    abortController,
    debugMode,
    new Set([agentId]),
    { text: "" },
  );
}

type AgentRunResult = {
  text: string;
  error?: string;
};

type DelegationInput = {
  agentId: string;
  instructions: string;
};

function parseDelegationInput(input: unknown): DelegationInput | null {
  let parsed = input;
  if (typeof input === "string") {
    try {
      parsed = JSON.parse(input);
    } catch {
      return null;
    }
  }

  if (!parsed || typeof parsed !== "object") return null;
  const { agent_id, instructions } = parsed as Record<string, unknown>;
  return typeof agent_id === "string" && typeof instructions === "string"
    ? { agentId: agent_id, instructions }
    : null;
}

function createToolResult(toolUseId: string, isError: boolean, content: string) {
  return {
    type: "tool_result",
    is_error: isError,
    content,
    tool_use_id: toolUseId,
  };
}

/**
 * Runs one agent turn. A delegate_task starts a child turn and then starts a
 * new turn for the delegating agent with the child's tool_result as input.
 */
async function* executeAgentConversation(
  agentId: string,
  message: string,
  request: ChatRequest,
  command: AgentCommand | null,
  abortController: AbortController,
  debugMode: boolean,
  delegationPath: Set<string>,
  result: AgentRunResult,
  suppressRunErrors = false,
): AsyncGenerator<StreamResponse> {
  const provider = globalRegistry.getProviderForAgent(agentId);
  const agentConfig = globalRegistry.getAgent(agentId);

  if (!provider || !agentConfig) {
    const error = `Agent '${agentId}' not found or provider not available`;
    result.error = error;
    if (!suppressRunErrors) yield { type: "error", error };
    return;
  }

  // Handle special commands
  if (command?.command === "capture_screen") {
    yield* handleScreenCapture(agentId, request, command, abortController, debugMode);
    return;
  }

  // Build provider request
  const providerRequest: ProviderChatRequest = {
    message,
    sessionId: request.sessionId,
    requestId: request.requestId,
    workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
  };

  // Execute with provider
  try {
    for await (const response of provider.executeChat(providerRequest, {
      debugMode,
      abortController,
      temperature: agentConfig.config?.temperature,
      maxTokens: agentConfig.config?.maxTokens,
    })) {
